actor SecureTokenStore {
    private let service = "com.fintrade.app.token"
    private let account = "apiToken"
    
    func save(token: String) throws {
        let data = Data(token.utf8)
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: account
        ]
        SecItemDelete(query as CFDictionary)
        let attributes: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: account,
            kSecValueData as String: data,
            kSecAttrAccessible as String: kSecAttrAccessibleAfterFirstUnlockThisDeviceOnly
        ]
        let status = SecItemAdd(attributes as CFDictionary, nil)
        guard status == errSecSuccess else { throw NSError(domain: "SecureTokenStore", code: Int(status)) }
    }
    
    func load() throws -> String? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: account,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        var result: CFTypeRef?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        guard status != errSecItemNotFound else { return nil }
        guard status == errSecSuccess, let data = result as? Data else { throw NSError(domain: "SecureTokenStore", code: Int(status)) }
        return String(data: data, encoding: .utf8)
    }
    
    func delete() {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: account
        ]
        SecItemDelete(query as CFDictionary)
    }
}

final class APIClient {
    static let shared = APIClient()
    
    private let baseURL: URL
    private let session: URLSession
    private let tokenStore = SecureTokenStore()
    private let decoder: JSONDecoder
    private let encoder: JSONEncoder
    
    private init(baseURL: URL = URL(string: "https://api.yourbrokerage.com")!) {
        self.baseURL = baseURL
        let configuration = URLSessionConfiguration.default
        configuration.waitsForConnectivity = true
        configuration.httpAdditionalHeaders = [
            "Content-Type": "application/json",
            "Accept": "application/json"
        ]
        self.session = URLSession(configuration: configuration)
        self.decoder = JSONDecoder()
        self.encoder = JSONEncoder()
        self.decoder.dateDecodingStrategy = .iso8601
        self.encoder.dateEncodingStrategy = .iso8601
    }
    
    func setAccessToken(_ token: String) async throws {
        try await tokenStore.save(token: token)
    }
    
    func clearAccessToken() async {
        await tokenStore.delete()
    }
    
    private func request<T: Decodable>(_ path: String, method: String = "GET", body: Encodable? = nil, retryOnUnauthorized: Bool = true) async throws -> T {
        var request = URLRequest(url: baseURL.appendingPathComponent(path))
        request.httpMethod = method
        if let token = try await tokenStore.load() {
            request.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        }
        if let body = body {
            request.httpBody = try encoder.encode(AnyEncodable(body))
        }
        
        let (data, response) = try await session.data(for: request)
        guard let http = response as? HTTPURLResponse else { throw URLError(.badServerResponse) }
        if http.statusCode == 401, retryOnUnauthorized {
            throw URLError(.userAuthenticationRequired)
        }
        guard (200...299).contains(http.statusCode) else {
            let message = String(data: data, encoding: .utf8) ?? "Request failed"
            throw NSError(domain: "APIClient", code: http.statusCode, userInfo: [NSLocalizedDescriptionKey: message])
        }
        return try decoder.decode(T.self, from: data)
    }
    
    func fetchQuote(symbol: String) async throws -> StockQuote {
        try await request("market/quotes/\(symbol)")
    }
    
    func fetchPortfolio() async throws -> [PortfolioPosition] {
        try await request("portfolio/positions")
    }
    
    func fetchAccountSummary() async throws -> AccountSummary {
        try await request("account/summary")
    }
    
    func submitOrder(_ order: TradeOrder) async throws -> TradeExecution {
        try await request("trades/orders", method: "POST", body: order)
    }
    
    func fetchOrders() async throws -> [TradeOrder] {
        try await request("trades/orders")
    }
}

struct AnyEncodable: Encodable {
    private let encodeClosure: (Encoder) throws -> Void
    
    init<T: Encodable>(_ wrapped: T) {
        self.encodeClosure = wrapped.encode
    }
    
    func encode(to encoder: Encoder) throws {
        try encodeClosure(encoder)
    }
}

@MainActor
final class TradingViewModel: ObservableObject {
    @Published var quotes: [String: StockQuote] = [:]
    @Published var positions: [PortfolioPosition] = []
    @Published var accountSummary = AccountSummary(cash: 0, buyingPower: 0, equity: 0, dayChange: 0, dayChangePercent: 0)
    @Published var recentExecutions: [TradeExecution] = []
    @Published var watchlist: [String] = ["AAPL", "MSFT", "NVDA", "AMZN", "TSLA"]
    @Published var selectedSymbol: String = "AAPL"
    @Published var isConnected: Bool = false
    @Published var isLoading: Bool = false
    @Published var errorMessage: String?
    
    private let api = APIClient.shared
    private var refreshTask: Task<Void, Never>?
    private var cancellables = Set<AnyCancellable>()
    
    func configure(token: String) {
        Task { try? await api.setAccessToken(token) }
        startLiveUpdates()
    }
    
    func startLiveUpdates() {
        refreshTask?.cancel()
        refreshTask = Task {
            await MainActor.run {
                self.isConnected = true
            }
            while !Task.isCancelled {
                await refreshMarketData()
                try? await Task.sleep(nanoseconds: 2_000_000_000)
            }
            await MainActor.run {
                self.isConnected = false
            }
        }
    }
    
    func stopLiveUpdates() {
        refreshTask?.cancel()
        refreshTask = nil
    }
    
    func refreshAll() async {
        await refreshMarketData()
        await loadPortfolio()
    }
    
    func refreshMarketData() async {
        do {
            async let summary = api.fetchAccountSummary()
            async let portfolio = api.fetchPortfolio()
            let quotes = try await withThrowingTaskGroup(of: StockQuote.self) { group -> [StockQuote] in
                for symbol in watchlist {
                    group.addTask { try await self.api.fetchQuote(symbol: symbol) }
                }
                var results: [StockQuote] = []
                for try await quote in group {
                    results.append(quote)
                }
                return results
            }
            let fetchedSummary = try await summary
            let fetchedPositions = try await portfolio
            await MainActor.run {
                self.accountSummary = fetchedSummary
                self.positions = fetchedPositions
                self.quotes = Dictionary(uniqueKeysWithValues: quotes.map { ($0.symbol, $0) })
                self.errorMessage = nil
            }
        } catch {
            await MainActor.run {
                self.errorMessage = error.localizedDescription
            }
        }
    }
    
    func loadPortfolio() async {
        do {
            let fetchedPositions = try await api.fetchPortfolio()
            let fetchedSummary = try await api.fetchAccountSummary()
            await MainActor.run {
                self.positions = fetchedPositions
                self.accountSummary = fetchedSummary
            }
        } catch {
            await MainActor.run {
                self.errorMessage = error.localizedDescription
            }
        }
    }
    
    func executeTrade(symbol: String, side: TradeSide, orderType: OrderType, quantity: Double, limitPrice: Double?) async -> Bool {
        guard quantity > 0 else {
            await MainActor.run { self.errorMessage = "Quantity must be greater than zero." }
            return false
        }
        await MainActor.run { self.isLoading = true }
        defer { Task { @MainActor in self.isLoading = false } }
        
        let order = TradeOrder(symbol: symbol, side: side, orderType: orderType, quantity: quantity, limitPrice: limitPrice)
        do {
            let execution = try await api.submitOrder(order)
            await MainActor.run {
                self.recentExecutions.insert(execution, at: 0)
                self.errorMessage = nil
            }
            await loadPortfolio()
            return true
        } catch {
            await MainActor.run {
                self.errorMessage = error.localizedDescription
            }
            return false
        }
    }
    
    func addToWatchlist(_ symbol: String) {
        guard !symbol.isEmpty else { return }
        let normalized = symbol.uppercased()
        guard !watchlist.contains(normalized) else { return }
        watchlist.insert(normalized, at: 0)
    }
    
    func removeFromWatchlist(at offsets: IndexSet) {
        watchlist.remove(atOffsets: offsets)
    }
    
    func quote(for symbol: String) -> StockQuote? {
        quotes[symbol]
    }
    
    func position(for symbol: String) -> PortfolioPosition? {
        positions.first { $0.symbol == symbol }
    }
    
    func totalMarketValue() -> Double {
        positions.reduce(0) { $0 + $1.marketValue }
    }
    
    func totalUnrealizedPnL() -> Double {
        positions.reduce(0) { $0 + $1.unrealizedPnL }
    }
}

